#include<bits/stdc++.h>
using namespace std;
const long long mod = 998244353;
int T,idid,n,m,bool_c,bool_f;
long long d[1005][1005],s[1005][1005];
long long h[1005][1005],ansc,ansf;
bool a[1005][1005];
int main(){
    cin>>T>>idid;
    while(T--){
        memset(d,0,sizeof(d));
        memset(s,0,sizeof(s));
        memset(h,0,sizeof(h));
        ansc=0,ansf=0;
        cin>>n>>m>>bool_c>>bool_f;
        for(int i=1;i<=n;i++)
            for(int j=1;j<=m;j++){
                char ch;cin>>ch;
                if(ch=='1')a[i][j]=1;
                else a[i][j]=0;
            }
        for(int i=1;i<=n;i++){
            d[i][m+1]=-1;
            for(int j=m;j>=1;j--)
                if(a[i][j])d[i][j]=-1;
                else d[i][j]=d[i][j+1]+1;
            for(int j=1;j<=m;j++)d[i][j]=max(d[i][j],0ll);
        }
        for(int i=3;i<=n;i++)
            for(int j=1;j<=m;j++)
                if(a[i][j])s[i][j]=0;
                else if(a[i-1][j])s[i][j]=0;
                else if(a[i-2][j])s[i][j]=0;
                else s[i][j]=s[i-1][j]+d[i-2][j];
        for(int j=1;j<=m;j++){
            h[n+1][j]=-1;
            for(int i=n;i>=1;i--)
                if(a[i][j])h[i][j]=-1;
                else h[i][j]=h[i+1][j]+1;
            for(int i=1;i<=n;i++)h[i][j]=max(h[i][j],0ll);
        }
        for(int i=1;i<=n;i++)
            for(int j=1;j<=m;j++){
                ansc=(ansc+s[i][j]*d[i][j])%mod;
                ansf=(ansf+s[i][j]*d[i][j]*h[i][j])%mod;
            }
        cout<<ansc*bool_c<<" "<<ansf*bool_f<<"\n";
    }
    return 0;
}
